const r=document.getElementById("navbar");window.addEventListener("scroll",()=>{window.scrollY>60?r?.classList.add("bg-void/95","backdrop-blur-md","border-b","border-gold/10","shadow-xl"):r?.classList.remove("bg-void/95","backdrop-blur-md","border-b","border-gold/10","shadow-xl")});const d=document.getElementById("menu-toggle"),t=document.getElementById("mobile-menu");d?.addEventListener("click",()=>{t?.classList.toggle("hidden")});const l=new IntersectionObserver(e=>{e.forEach(o=>{o.isIntersecting&&o.target.classList.add("visible")})},{threshold:.12,rootMargin:"0px 0px -40px 0px"});document.querySelectorAll(".reveal, .reveal-left, .reveal-right").forEach(e=>{l.observe(e)});
